targets.expr:
sum by (namespace) (
  rate(http_requests_total{
    job=~"fastapi-app-.*-backend",
    status!~"2xx|3xx",
    handler!="/metrics"
  }[5m])
)
/
sum by (namespace) (
  rate(http_requests_total{
    job=~"fastapi-app-.*-backend",
    handler!="/metrics"
  }[5m])
)

histogram_quantile(
  0.95,
  sum by (le, namespace) (
    rate(
      http_request_duration_seconds_bucket{
        job=~"fastapi-app-.*-backend",
        handler!="/metrics"
      }[5m]
    )
  )
)

sum(
  max by (namespace, pod, container) (
    container_memory_rss{
      job="kubelet",
      metrics_path="/metrics/cadvisor",
      container!="",
      image!=""
    }
  )
) by (namespace)

sum without (device) (
  max without (fstype, mountpoint) (
    (
      node_filesystem_size_bytes{job="node-exporter", fstype!="", mountpoint!=""}
      -
      node_filesystem_avail_bytes{job="node-exporter", fstype!="", mountpoint!=""}
    ) != 0
  )
)
/
scalar(
  sum(
    max without (fstype, mountpoint) (
      node_filesystem_size_bytes{job="node-exporter", fstype!="", mountpoint!=""}
    )
  )
)

sum(
  max by (cluster, namespace, pod, container)(
    kube_pod_container_resource_requests{
      job="kube-state-metrics",
      resource="memory"
    }
  )
* on(cluster, namespace, pod)
  group_left(workload, workload_type)
  namespace_workload_pod:kube_pod_owner:relabel
) by (workload, workload_type)

